-- Calibration seeds generated from the approved workbook.

on conflict (motif) do update set status = excluded.status, reason = excluded.reason, replacement_direction = excluded.replacement_direction, is_active = true;

on conflict (lower(trim(response_text))) do update set verdict = excluded.verdict, origin = excluded.origin, source_category = excluded.source_category, source_scenario = excluded.source_scenario, source_scenario_id = excluded.source_scenario_id, notes = excluded.notes, is_active = true;
